    (name: 'Attunement Signals', description: 'Measures noticing the partner\'s mood, needs, or distress without being told explicitly.'),
    (name: 'Positive Reframing', description: 'Detects finding silver linings, growth opportunities, or constructive angles in difficult situations.'),
    (name: 'Commitment Language', description: 'Tracks expressions of dedication, long-term thinking, and investment in the relationship\'s future.'),
    (name: 'Flexibility Demonstration', description: 'Identifies willingness to adapt plans, adjust expectations, or meet the partner halfway.'),
    (name: 'Protective Language', description: 'Looks for statements showing the partner\'s safety, wellbeing, and interests matter deeply.'),
    (name: 'Celebration of Milestones', description: 'Measures acknowledging anniversaries, achievements, or meaningful moments together.'),
    (name: 'Constructive Feedback', description: 'Detects offering suggestions for improvement that are kind, specific, and growth-focused.'),
    (name: 'Presence During Hardship', description: 'Identifies staying engaged when the partner is struggling, grieving, or facing challenges.'),
    (name: 'Admiration Expression', description: 'Tracks genuine respect for the partner\'s character, strength, intelligence, or resilience.'),
    (name: 'Playfulness Indicators', description: 'Looks for lighthearted teasing, inside jokes, or fun interactions that strengthen bonding.'),
    (name: 'Empathic Mirroring', description: 'Measures reflecting back the partner\'s emotions to show understanding and validation.'),
    (name: 'Acceptance Language', description: 'Detects embracing the partner as they are, including flaws, without demanding change.'),
    (name: 'Supportive Presence', description: 'Identifies being there without fixing, offering comfort through listening and companionship.'),
    (name: 'Genuine Interest', description: 'Tracks asking follow-up questions and remembering details about the partner\'s life and concerns.'),
