    (name: 'Mutual Encouragement', description: 'Identifies both partners cheering each other on and celebrating efforts not just outcomes.'),
    (name: 'Respectful Questioning', description: 'Tracks asking about the partner\'s perspective with genuine curiosity rather than interrogation.'),
    (name: 'Loving Consistency', description: 'Measures showing up the same way in good times and hard times, reliable in affection.'),
    (name: 'Emotional Reciprocity', description: 'Looks for both partners sharing feelings, needs, and vulnerabilities in balanced ways.'),
    (name: 'Joyful Presence', description: 'Detects genuine happiness in the partner\'s company and enthusiasm for time together.'),
    (name: 'Constructive Dialogue', description: 'Identifies conversations that move toward understanding rather than winning or proving right.'),
    (name: 'Protective Advocacy', description: 'Tracks standing up for the partner, defending them, and prioritizing their wellbeing.'),
    (name: 'Mindful Communication', description: 'Measures thoughtful word choice, considering impact before speaking, and intentional messaging.'),
    (name: 'Relationship Investment', description: 'Looks for time, energy, and resources devoted to nurturing the partnership.'),
    (name: 'Secure Base Language', description: 'Detects offering stability, safety, and a foundation from which the partner can explore.'),
    (name: 'Mutual Admiration', description: 'Identifies both partners expressing respect and appreciation for each other\'s qualities.'),
    (name: 'Tender Moments', description: 'Tracks creating or recognizing intimate quiet moments of connection and closeness.'),
    (name: 'Genuine Curiosity', description: 'Looks for authentic interest in understanding the partner\'s thoughts, feelings, and experiences.'),
    (name: 'Loving Acceptance', description: 'Detects embracing the partner\'s whole self, including imperfections and past.'),
    (name: 'Mutual Growth Support', description: 'Identifies both partners encouraging each other\'s development and celebrating progress.'),
    (name: 'Warm Tone Indicators', description: 'Tracks use of affectionate language, kind phrasing, and gentle communication style.'),
    (name: 'Responsive Engagement', description: 'Measures quick, engaged responses to the partner\'s messages and emotional bids.'),
    (name: 'Shared Values Alignment', description: 'Looks for references to common beliefs, goals, or life philosophies that unite the couple.'),
    (name: 'Unconditional Support', description: 'Detects standing by the partner through difficulties without making support conditional.'),
    (name: 'Intimate Vulnerability', description: 'Identifies sharing deep fears, dreams, or insecurities that deepen emotional bonds.'),
    (name: 'Mutual Respect Language', description: 'Tracks honoring each other\'s perspectives, choices, and autonomy in communication.'),
    (name: 'Positive Framing', description: 'Measures seeing the best in situations and the partner, focusing on strengths.'),
    (name: 'Collaborative Problem Solving', description: 'Looks for working together toward solutions that benefit both partners equally.'),
    (name: 'Emotional Validation', description: 'Detects confirming that the partner\'s feelings make sense and are acceptable.'),
    (name: 'Consistent Kindness', description: 'Identifies regular small acts of care that show the partner is thought of and valued.'),
    (name: 'Mutual Celebration', description: 'Tracks both partners genuinely happy about each other\'s successes and joys.'),
    (name: 'Secure Attachment Language', description: 'Measures expressing trust, comfort with intimacy, and confidence in the relationship.'),
    (name: 'Thoughtful Consideration', description: 'Looks for making decisions with the partner\'s needs and feelings in mind.'),
    (name: 'Loving Presence', description: 'Detects being fully present and engaged, showing the partner they matter most.'),
    (name: 'Genuine Care Language', description: 'Tracks authentic expressions of concern, care, and investment in the partner\'s wellbeing.'),
    (name: 'Relationship Commitment', description: 'Measures expressing dedication to the partnership and willingness to work through challenges.'),
    (name: 'Authentic Love Expression', description: 'Looks for genuine consistent expressions of love that feel real and unconditional.'),
