// THE BAD — 100 warning-sign / mid-severity harmful pattern metrics
// IDs: bad_1 … bad_100   severityWeight: 3
// ═══════════════════════════════════════════════════════════════════════════

List<PsychologicalMetric> _buildPackBadCatalog() {
  const defs = [
    (name: 'Passive Aggression', description: 'Detects indirect hostility through procrastination, forgetfulness, sarcasm, or subtle sabotage instead of direct expression.'),
    (name: 'Guilt Weaponization', description: 'Identifies using guilt, shame, or obligation language to manipulate decisions or prevent boundary-setting.'),
    (name: 'Emotional Blackmail', description: 'Flags threats of self-harm, abandonment, or withdrawal of love to control behavior or prevent discussion.'),
    (name: 'Chronic Complaining', description: 'Tracks persistent negativity, rumination, or complaint without seeking solutions or collaborative change.'),
    (name: 'Comparison Shaming', description: 'Identifies unfavorable comparisons to exes, friends, or family to shame or coerce behavior change.'),
    (name: 'Conditional Listening', description: 'Detects listening only when it benefits the listener or serves their agenda rather than genuine understanding.'),
    (name: 'Selective Memory', description: 'Tracks convenient forgetting of promises, agreements, or past harmful behavior to avoid accountability.'),
    (name: 'Attention Seeking Through Crisis', description: 'Identifies dramatic escalation, crisis creation, or exaggeration to gain focus or sympathy.'),
    (name: 'Boundary Testing', description: 'Detects repeated probing or pushing of stated limits to determine if they will be enforced.'),
    (name: 'Withholding Information', description: 'Identifies deliberate omission of relevant facts, context, or transparency to maintain control.'),
    (name: 'Disproportionate Anger', description: 'Tracks anger responses that are significantly larger than the triggering incident warrants.'),
    (name: 'Reassurance Addiction', description: 'Flags constant need for validation, repeated questions about commitment, or endless proof of love.'),
    (name: 'Conversation Avoidance', description: 'Detects refusal to engage with concerns, avoidance phrases, or shutting down important discussions.'),
    (name: 'Contradiction Pattern', description: 'Identifies contradictory statements, promises, or positions that create confusion or destabilization.'),
    (name: 'Dismissal Through Labeling', description: 'Flags labeling concerns as "crazy," "dramatic," "paranoid," or "overreacting" to invalidate them.'),
    (name: 'Selective Empathy', description: 'Detects empathy offered only when convenient or when it serves the speaker\'s interests.'),
    (name: 'Transactional Framing', description: 'Identifies "you owe me," "after all I\'ve done," or viewing relationship acts as creating debt.'),
    (name: 'Grievance Recycling', description: 'Tracks bringing up old grievances repeatedly or using past harm as ammunition in current conflicts.'),
    (name: 'Demand Language', description: 'Flags imperatives, commands, or ultimatums rather than requests or collaborative problem-solving.'),
    (name: 'Emotional Unavailability', description: 'Detects consistent refusal to engage emotionally, share feelings, or provide comfort.'),
    (name: 'Hostile Interpretation', description: 'Identifies taking neutral statements as attacks or interpreting ambiguous messages as hostile.'),
    (name: 'Entitlement Framing', description: 'Flags language suggesting the speaker deserves special treatment, exceptions, or priority.'),
    (name: 'Criticism Disguised as Help', description: 'Detects criticism wrapped in "I\'m just trying to help" or "for your own good" language.'),
    (name: 'Neglect Patterns', description: 'Identifies consistent failure to meet emotional, physical, or relational needs.'),
    (name: 'Conflict Rumination', description: 'Tracks obsessive rehashing of conflicts without moving toward resolution or closure.'),
    (name: 'Sensitivity Dismissal', description: 'Flags statements like "you\'re too sensitive" or "you\'re overreacting" to dismiss feelings.'),
    (name: 'Competitive Framing', description: 'Detects framing relationship as a competition where one partner must win or dominate.'),
    (name: 'Double Standards', description: 'Identifies applying different rules to self versus partner or changing expectations arbitrarily.'),
    (name: 'Affection as Punishment', description: 'Flags removing affection, attention, or communication as retaliation for perceived wrongs.'),
    (name: 'Blame Rotation', description: 'Tracks rotating blame between partner, circumstances, and external factors to avoid accountability.'),
    (name: 'Rhetorical Mockery', description: 'Detects rhetorical or sarcastic questions used to mock rather than understand.'),
    (name: 'Sacrifice Reminders', description: 'Identifies reminding partner of sacrifices, favors, or support to create debt and compliance.'),
    (name: 'Deliberate Escalation', description: 'Flags deliberately escalating intensity to overwhelm partner\'s ability to respond rationally.'),
    (name: 'Strategic Vulnerability', description: 'Detects sharing emotions only when it serves manipulation or control purposes.'),
    (name: 'Deflection Through Counterattack', description: 'Identifies turning focus away from partner\'s concerns by raising unrelated issues or countercharges.'),
    (name: 'Superiority Language', description: 'Flags superiority language, condescension, or framing partner as beneath them.'),
    (name: 'Conflict Exit Pattern', description: 'Detects pattern of leaving conversations, refusing to engage, or creating distance during conflict.'),
    (name: 'Negative Bias', description: 'Tracks consistently interpreting neutral or positive actions as negative or suspicious.'),
    (name: 'Agency Denial', description: 'Identifies "I have to," "you make me," or language removing personal agency from the speaker.'),
    (name: 'Silence as Control', description: 'Flags using silence or non-response as a form of punishment or control.'),
