    (name: 'Validity Denial', description: 'Identifies treating partner\'s feelings, needs, or concerns as invalid or illegitimate.'),
    (name: 'Advice Disguised Criticism', description: 'Flags criticism presented as concern, advice, or a helpful observation.'),
    (name: 'Superiority Indicators', description: 'Detects superiority, mockery, or disdain in language or communication style.'),
    (name: 'Repair Resistance', description: 'Tracks resistance to making amends, reconnecting, or rebuilding after conflict.'),
    (name: 'Effort Dismissal', description: 'Flags minimizing or ignoring partner\'s attempts to improve or address issues.'),
    (name: 'Emotional Distance Pattern', description: 'Detects long-term pattern of emotional distance or refusal to engage authentically.'),
    (name: 'Inferiority Framing', description: 'Identifies framing partner as inferior, flawed, or unworthy of full respect.'),
    (name: 'Feedback Resistance', description: 'Detects resistance to hearing criticism, refusing to listen, or shutting down discussion.'),
    (name: 'Worry Dismissal', description: 'Identifies treating partner\'s worries or fears as unfounded or irrational.'),
    (name: 'Fault Finding', description: 'Flags chronic pattern of finding fault, complaining about, or attacking partner\'s character.'),
    (name: 'Sacrifice Guilt Cycling', description: 'Identifies repeatedly bringing up past support to create guilt or control behavior.'),
    (name: 'Commitment Ambiguity', description: 'Tracks unclear or wavering commitment language, mixed signals, or reluctance to commit.'),
    (name: 'Request Dismissal', description: 'Flags ignoring, refusing, or delaying response to partner\'s reasonable requests.'),
    (name: 'Emotional Control Tactics', description: 'Detects strategic use of emotions to control outcomes or prevent accountability.'),
    (name: 'Exchange Mentality', description: 'Flags viewing relationship through lens of debt, obligation, or transactional exchange.'),
    (name: 'Personal Development Resistance', description: 'Detects resistance to personal development, learning, or changing harmful patterns.'),
    (name: 'Improvement Rejection', description: 'Identifies minimizing or rejecting partner\'s efforts to improve or address issues.'),
    (name: 'Chronic Criticism', description: 'Flags chronic pattern of criticism wrapped in concern, helpfulness, or care language.'),
    (name: 'Solution Avoidance', description: 'Detects consistent pattern of avoiding closure, moving forward, or finding workable solutions.'),
    (name: 'Blame Deflection Pattern', description: 'Flags habitual pattern of redirecting responsibility to external factors or the partner.'),
    (name: 'Dismissive Responses', description: 'Identifies pattern of dismissing partner\'s input, ideas, or suggestions without consideration.'),
    (name: 'Resentment Expression', description: 'Detects tone of resentment, bitterness, or long-held frustration in communication.'),
    (name: 'Ambivalent Messaging', description: 'Flags mixed messages about commitment, unclear desire to continue, or push-pull dynamics.'),
    (name: 'Expectation Shifting', description: 'Identifies changing expectations without communication, then blaming partner for not meeting them.'),
    (name: 'Deflection Habit', description: 'Detects habitual avoidance of direct answers or redirection of conversations away from accountability.'),
    (name: 'Manipulation Through Kindness', description: 'Flags exaggerated generosity used strategically to create obligation or lower defenses.'),
    (name: 'Chronic Lateness Pattern', description: 'Identifies consistent disregard for partner\'s time through lateness or broken scheduling commitments.'),
    (name: 'Progress Minimization', description: 'Tracks dismissing or failing to acknowledge the partner\'s genuine personal growth or improvements.'),
    (name: 'Emotional Weaponizing', description: 'Detects using partner\'s disclosed vulnerabilities or fears against them in conflict.'),
    (name: 'Gaslighting-Adjacent Tactics', description: 'Identifies subtle reality-distorting tactics that create self-doubt without full gaslighting.'),
    (name: 'Passive Stonewalling', description: 'Flags subtle disengagement, monosyllabic responses, or checked-out presence as avoidance.'),
