    (name: 'Slavery Language', description: 'Identifies language treating partner as property, slave, or wholly owned person without rights.'),
    (name: 'Debt Bondage Threats', description: 'Detects threats to trap partner through manufactured debt or financial obligation.'),
    (name: 'Forced Labor Demands', description: 'Flags demands for unpaid labor, servitude, or work under threat of harm or punishment.'),
    (name: 'Exploitation Normalization', description: 'Identifies framing severe exploitation as normal, deserved, consensual, or even beneficial.'),
    (name: 'Vulnerability Targeting', description: 'Identifies deliberate targeting of isolated, economically dependent, or psychologically vulnerable individuals.'),
    (name: 'Trauma Bonding Engineering', description: 'Detects deliberate creation of fear-relief cycles designed to create deep emotional dependency.'),
    (name: 'Intermittent Reinforcement Abuse', description: 'Flags unpredictable cycles of reward and severe punishment used to create psychological addiction.'),
    (name: 'Learned Helplessness Induction', description: 'Identifies systematic removal of agency, resources, and perceived escape options.'),
    (name: 'Identity Erasure Language', description: 'Flags demands to abandon personality, interests, appearance, or core sense of identity.'),
    (name: 'Autonomy Annihilation', description: 'Detects systematic elimination of independent thought, decision-making, or personal agency.'),
    (name: 'Thought Control Tactics', description: 'Flags demands to think, believe, or feel only as the controlling partner dictates.'),
    (name: 'Emotional Numbness Enforcement', description: 'Identifies punishment for showing emotions or explicit demands to suppress all feelings.'),
    (name: 'Complex Trauma Creation', description: 'Flags systematic patterns creating complex PTSD-level trauma through chronic abuse.'),
    (name: 'Betrayal Trauma Infliction', description: 'Identifies deliberate betrayal designed to shatter foundational trust and psychological safety.'),
    (name: 'Moral Injury Language', description: 'Detects forcing partner to violate their own deeply held values or commit harmful acts.'),
    (name: 'Existential Threat Language', description: 'Flags threats to partner\'s existence, core identity, sanity, or will to live.'),
    (name: 'Suicide Coercion Language', description: 'Identifies pushing partner toward suicidal ideation through sustained abuse and manufactured hopelessness.'),
    (name: 'Justification Mythology', description: 'Identifies elaborate invented narratives presented to justify abuse as necessary, deserved, or righteous.'),
    (name: 'Victim Narrative Inversion', description: 'Detects complete reversal where the abuser claims to be the real victim of their own abuse.'),
    (name: 'Abuse Normalization Preaching', description: 'Flags teaching or insisting that abuse is normal, healthy, or beneficial for the partner.'),
    (name: 'Predatory Ideology', description: 'Identifies ideological justification for exploitation, dominance, or harm toward the partner.'),
    (name: 'Cult Leader Messaging', description: 'Detects messaging claiming special knowledge, divine right, or superior authority over the partner.'),
    (name: 'Grooming Timeline Language', description: 'Flags references to a long-term manipulation plan or descriptions of a grooming progression.'),
    (name: 'Chronic Humiliation Campaign', description: 'Identifies sustained pattern of public or private humiliation designed to destroy self-worth.'),
    (name: 'Safety Exit Blocking', description: 'Detects actively preventing the partner from accessing escape routes, support systems, or safety resources.'),
    (name: 'Document Confiscation Threats', description: 'Flags threats or actions to take, hide, or destroy identity documents to prevent escape.'),
    (name: 'Violent Jealousy Patterns', description: 'Identifies jealousy that has escalated to explicit threats, surveillance, or violent retaliation.'),
    (name: 'Rage Explosion Patterns', description: 'Detects descriptions or patterns of explosive violent outbursts disproportionate to any trigger.'),
    (name: 'Coercive Control Escalation', description: 'Tracks increasing severity and breadth of coercive control tactics over time.'),
    (name: 'Fear-Based Compliance Language', description: 'Identifies compliance driven entirely by fear of violence or severe punishment rather than choice.'),
    (name: 'Punishment Ritual Language', description: 'Detects references to systematic punishment practices used to enforce compliance and control.'),
    (name: 'Degradation Ritual Indicators', description: 'Flags systematic degradation or humiliation rituals designed to destroy dignity.'),
    (name: 'Non-Consensual Exposure Threats', description: 'Identifies threats to expose intimate images, private information, or secrets without consent.'),
    (name: 'Image-Based Abuse Threats', description: 'Detects threats to distribute intimate images as revenge, punishment, or blackmail.'),
    (name: 'Financial Entrapment Tactics', description: 'Flags deliberate creation of financial dependency making independent survival impossible.'),
    (name: 'Housing Threat Language', description: 'Detects threats to make partner homeless, remove housing access, or destroy shelter security.'),
    (name: 'Immigration Status Threats', description: 'Identifies threats to report immigration status or revoke visa sponsorship as control.'),
    (name: 'Religious or Spiritual Abuse', description: 'Detects using religious authority, doctrine, or spiritual threat to control, punish, or harm.'),
    (name: 'Cultural Shame Weaponization', description: 'Flags threatening to expose behaviors to cultural or family community as punishment.'),
    (name: 'Family Harm Threats', description: 'Identifies threats to harm partner\'s family members, children, or loved ones as leverage.'),
    (name: 'Coordinated Harassment Campaign', description: 'Detects organizing others to collectively harass, stalk, or intimidate the partner.'),
    (name: 'False Police Report Threats', description: 'Flags threatening to make false police reports or legal accusations against the partner.'),
    (name: 'Legal System Weaponization', description: 'Identifies using legal processes, courts, or protective orders as weapons of harassment.'),
    (name: 'Restraining Order Violation', description: 'Detects references to violating or planning to violate protective or no-contact orders.'),
    (name: 'Workplace Sabotage Threats', description: 'Flags threats to contact employer, colleagues, or clients to destroy partner\'s livelihood.'),
    (name: 'Social Annihilation Threats', description: 'Detects threats to destroy partner\'s reputation, relationships, and social standing.'),
    (name: 'Systematic Deception Campaign', description: 'Identifies long-term elaborate deception designed to exploit the partner financially or emotionally.'),
    (name: 'Property Destruction as Terror', description: 'Identifies deliberate destruction of partner\'s property as an intimidation tactic.'),
    (name: 'Animal Cruelty as Proxy Terror', description: 'Detects harming or threatening pets to demonstrate capacity for violence to partner.'),
    (name: 'Child Endangerment Language', description: 'Flags placing children in dangerous situations or threatening to do so as leverage.'),
    (name: 'Disability-Based Control', description: 'Detects exploiting partner\'s disability by controlling access to medication, mobility, or care.'),
    (name: 'Crisis Manufactured Control', description: 'Flags deliberately creating emergencies or crises to increase partner dependency or justify monitoring.'),
    (name: 'Isolation from Emergency Services', description: 'Identifies actively preventing partner from calling police, ambulance, or crisis services.'),
    (name: 'Threat Escalation Trajectory', description: 'Tracks measurable increase in severity, specificity, or frequency of threats over time.'),
    (name: 'Lethality Assessment Indicators', description: 'Flags combinations of factors associated with highest risk of intimate partner homicide.'),
    (name: 'Psychological Torture Tactics', description: 'Identifies sustained psychological abuse designed to break the partner\'s mental stability.'),
    (name: 'Captivity Language', description: 'Detects references to holding partner captive, preventing departure, or controlling all movement.'),
    (name: 'Targeted Violence Planning', description: 'Detects any language indicating planning, preparation, or countdown to violence against partner.'),
    (name: 'Third Party Threat Recruitment', description: 'Identifies recruiting friends, family, or others to threaten or harm the partner.'),
    (name: 'Suicidal Ideation Exploitation', description: 'Flags exploiting partner\'s suicidal crisis as leverage or to prevent them seeking help.'),
    (name: 'Poisoning or Drugging Threats', description: 'Detects threats or references to drugging, poisoning, or tampering with partner\'s food or drink.'),
    (name: 'Non-Suicidal Self-Harm Exploitation', description: 'Flags exploiting partner\'s self-harm behavior as leverage, mockery, or further control.'),
    (name: 'Dissociation Induction Language', description: 'Detects patterns designed to cause dissociation, detachment, or depersonalization in the partner.'),
    (name: 'Cognitive Distortion Implanting', description: 'Detects deliberate installation of false beliefs about self, reality, or the partner\'s own sanity.'),
    (name: 'Medical Care Obstruction', description: 'Detects preventing access to medication, doctors, hospitals, or health treatment.'),
    (name: 'Extremist Threat Language', description: 'Flags language borrowed from extremist or violent ideological frameworks applied toward the partner.'),
  ];
  return List<PsychologicalMetric>.generate(
    defs.length,
    (i) => PsychologicalMetric(
      id: 'ugly_${i + 1}',
      name: defs[i].name,
      description: defs[i].description,
      severityWeight: 5,
    ),
    growable: false,
  );
}
